<style lang="scss">
  @use "$lib/env";
  @use "$lib/scss/mixins/scr";

  @keyframes animate-circle {
    0% {
      width: 0;
      opacity: 0;
    }

    50% {
      opacity: .5;
    }
    100% {
      width: 800px;
      opacity: 0;
    }
  }

  @keyframes animate-bg {
    0% {
      opacity: 1;
    }
    100% {
      opacity: 0;
    }
  }
  @keyframes animate-text {
    0% {
      transform: scale(.8);
      opacity: 0;
    }

    100% {
      transform: scale(1);
      opacity: 1;
    }
  }

  .bg2 {
    position: fixed;
    top: 0;
    left: 0;
    bottom: 0;
    right: 0;

    z-index: 99;

    background-size: 270%;
    background-position: center -500px;

    @media (min-width: 375px) {
      background-position: center calc((100vw - 875px) * 1);
    }

    @include scr.tablet {
      background-size: 150%;
      background-position: center;
    }

    @include scr.desktop {
      background-size: cover;
      background-position: center -800px;
      @media (min-width: 1600px) {
        background-position: center -1300px;
      }
    }

    opacity: 1;

    transition-property: transform, opacity;
    transition-duration: 1000ms;

    @media (min-width: env.$tablet-width) {
      :global svg {
        *[fill=black] {
          fill: #fff;
        }
      }
    }

    @include scr.tablet-and-lower{
      background-image: var(--bg-mobile);
    }

    @include scr.desktop {
      background-image: var(--bg-desktop);
    }

    &.hidden {
      opacity: 0;
    }

    &.hidden &-content {
      height: 600px;
      opacity: 0;

      & > div {
        transform: translateX(100px);
        @media (min-width: env.$tablet-width) {
          transform: translate(-50%, -300px);
        }
      }
    }

    &-content {
      display: flex;

      position: absolute;
      bottom: 0;
      right: 0;
      left: 50%;
      top: 54px;
      transform: translateX(-50%);

      height: 475px;
      transition-property: height, opacity;
      transition-duration: 1000ms;
      width: 60%;

      svg {
        width: 100%;
        height: inherit;
      }
    }
  }

  .bg {
    position: fixed;
    top: 0;
    left: 0;
    bottom: 0;
    right: 0;

    z-index: 100;

    transition: opacity 700ms;
    background-color: #000;
    background-size: cover;

    @media (max-width: env.$tablet-width) {
      background-image: var(--bg-mobile);
    }

    @media (min-width: env.$tablet-width) {
      background-image: var(--bg-desktop);
    }

    &.hidden {
      opacity: 0;
    }

    &::before {
      content: '';
      position: absolute;

      top: 0;
      left: 0;
      right: 0;
      bottom: 0;
      background-color: #0D0F10;
      opacity: 0;

      animation: 1000ms animate-bg linear;
    }
  }

  .content {
    position: fixed;
    top: 50%;
    left: 50%;
    transform: translate(-50%, -50%);

    opacity: 1;
    z-index: 100;

    transition-property: transform, opacity;
    transition-duration: 700ms;

    &.hidden {
      opacity: 0;
      transform: translate(-50%, -65%);
    }

    .circle {
      :global svg {
        opacity: 0;
        position: absolute;
        top: 50%;
        left: 50%;
        transform: translate(-50%, -50%);

        animation: 1000ms animate-circle;
        height: auto;
      }
    }
  }

  .text {
    color: #F0F3F5;
    font-size: 10px;
    text-align: center;

    animation: animate-text 1000ms;

    :global svg {
      display: block;
      max-width: fit-content;
      margin-left: auto;
      margin-right: auto;

      width: auto;
      height: 120px;
    }

    div {
      margin-top: 10px;
    }
  }
</style>